// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/campaign-creators/force-cleanup", wrapper.ForceCleanupCampaignCreator)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/campaigns/{id}/mark-deleted", wrapper.MarkCampaignDeleted)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/cleanup-entity", wrapper.CleanupEntity)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/test/reset-tokens", wrapper.GetResetToken)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/seed-telegram-message", wrapper.SeedTelegramMessage)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/seed-user", wrapper.SeedUser)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/test/telegram-messages", wrapper.CleanupTelegramMessages)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/telegram/message", wrapper.SendTelegramMessage)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/test/telegram/sent", wrapper.GetTelegramSent)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/telegram/spy/fail-next", wrapper.TelegramSpyFailNext)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/telegram/spy/fake-chat", wrapper.TelegramSpyFakeChat)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/tma/sign-init-data", wrapper.SignTMAInitData)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/trustme/run-outbox-once", wrapper.TrustMeRunOutboxOnce)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/trustme/spy-clear", wrapper.TrustMeSpyClear)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/trustme/spy-clear-fail", wrapper.TrustMeSpyClearFail)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/trustme/spy-fail", wrapper.TrustMeSpyFail)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/test/trustme/spy-list", wrapper.TrustMeSpyList)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/test/trustme/spy-register-document", wrapper.TrustMeSpyRegisterDocument)
	})

	return r
}

