// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Hard-delete a campaign_creators row regardless of soft-deleted state
	// (POST /test/campaign-creators/force-cleanup)
	ForceCleanupCampaignCreator(ctx context.Context, request ForceCleanupCampaignCreatorRequestObject) (ForceCleanupCampaignCreatorResponseObject, error)
	// Flip campaigns.is_deleted = true without going through admin flows
	// (POST /test/campaigns/{id}/mark-deleted)
	MarkCampaignDeleted(ctx context.Context, request MarkCampaignDeletedRequestObject) (MarkCampaignDeletedResponseObject, error)
	// Hard-delete a test entity (user or brand) and its references
	// (POST /test/cleanup-entity)
	CleanupEntity(ctx context.Context, request CleanupEntityRequestObject) (CleanupEntityResponseObject, error)
	// Get the raw reset token captured for the given email
	// (GET /test/reset-tokens)
	GetResetToken(ctx context.Context, request GetResetTokenRequestObject) (GetResetTokenResponseObject, error)
	// Insert a synthetic row into telegram_messages
	// (POST /test/seed-telegram-message)
	SeedTelegramMessage(ctx context.Context, request SeedTelegramMessageRequestObject) (SeedTelegramMessageResponseObject, error)
	// Create a test user with given credentials and role
	// (POST /test/seed-user)
	SeedUser(ctx context.Context, request SeedUserRequestObject) (SeedUserResponseObject, error)
	// Hard-delete telegram_messages rows by chat_id
	// (DELETE /test/telegram-messages)
	CleanupTelegramMessages(ctx context.Context, request CleanupTelegramMessagesRequestObject) (CleanupTelegramMessagesResponseObject, error)
	// Inject a synthetic text message into the Telegram handler
	// (POST /test/telegram/message)
	SendTelegramMessage(ctx context.Context, request SendTelegramMessageRequestObject) (SendTelegramMessageResponseObject, error)
	// Read recorded outbound Telegram messages
	// (GET /test/telegram/sent)
	GetTelegramSent(ctx context.Context, request GetTelegramSentRequestObject) (GetTelegramSentResponseObject, error)
	// Force the next outbound bot send to chatId to fail
	// (POST /test/telegram/spy/fail-next)
	TelegramSpyFailNext(ctx context.Context, request TelegramSpyFailNextRequestObject) (TelegramSpyFailNextResponseObject, error)
	// Mark chatId as test-synthetic so TeeSender skips the real bot
	// (POST /test/telegram/spy/fake-chat)
	TelegramSpyFakeChat(ctx context.Context, request TelegramSpyFakeChatRequestObject) (TelegramSpyFakeChatResponseObject, error)
	// Mint a valid Telegram WebApp initData payload for tests
	// (POST /test/tma/sign-init-data)
	SignTMAInitData(ctx context.Context, request SignTMAInitDataRequestObject) (SignTMAInitDataResponseObject, error)
	// Synchronously run one tick of the contract outbox-worker
	// (POST /test/trustme/run-outbox-once)
	TrustMeRunOutboxOnce(ctx context.Context, request TrustMeRunOutboxOnceRequestObject) (TrustMeRunOutboxOnceResponseObject, error)
	// Clear the TrustMe spy store
	// (POST /test/trustme/spy-clear)
	TrustMeSpyClear(ctx context.Context, request TrustMeSpyClearRequestObject) (TrustMeSpyClearResponseObject, error)
	// Drop the spy fail registration for the IIN
	// (POST /test/trustme/spy-clear-fail)
	TrustMeSpyClearFail(ctx context.Context, request TrustMeSpyClearFailRequestObject) (TrustMeSpyClearFailResponseObject, error)
	// Make every TrustMe SendToSign for the IIN fail until cleared
	// (POST /test/trustme/spy-fail)
	TrustMeSpyFail(ctx context.Context, request TrustMeSpyFailRequestObject) (TrustMeSpyFailResponseObject, error)
	// Read recorded outbound TrustMe SendToSign requests
	// (GET /test/trustme/spy-list)
	TrustMeSpyList(ctx context.Context, request TrustMeSpyListRequestObject) (TrustMeSpyListResponseObject, error)
	// Pre-register a TrustMe-known document for Phase 0 recovery
	// (POST /test/trustme/spy-register-document)
	TrustMeSpyRegisterDocument(ctx context.Context, request TrustMeSpyRegisterDocumentRequestObject) (TrustMeSpyRegisterDocumentResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

